{
 "level": "B1–B2",
 "intro": "In this topic, you will learn which <strong>verbs CANNOT form the passive</strong> and why. This is important to avoid grammatical errors.",
 "rules": [
 {
 "label": "Intransitive",
 "color": "rose",
 "text": "<strong>Intransitive verbs</strong> (without an object) — without a passive:",
 "example": "He arrived. ✅"
 },
 {
 "label": "Verbs of state",
 "color": "amber",
 "text": "Some <strong>stative verbs</strong> are without a passive:",
 "example": "I have a car. ✅"
 },
 {
 "label": "Reverse",
 "color": "blue",
 "text": "<strong>Reverse verbs</strong> — without passive:",
 "example": "She washed herself. ✅"
 }
 ]
}

{
 "title": "1. Intransitive Verbs",
 "intro": "Verbs without a direct object <strong>do not form the passive</strong>:",
 "items": [
 {
 "label": "arrive",
 "title": "arrive",
 "subtitle": "He arrived. ✅"
 },
 {
 "label": "go",
 "title": "to go",
 "subtitle": "They went home. ✅"
 },
 {
 "label": "come",
 "title": "come",
 "subtitle": "She came early. ✅ (no passive)"
 },
 {
 "label": "sleep",
 "title": "sleep",
 "subtitle": "He slept well. ✅ (no passive)"
 },
 {
 "label": "die",
 "title": "to die",
 "subtitle": "The king died. ✅ (no passive)"
 },
 {
 "label": "happen",
 "title": "occur",
 "subtitle": "It happened yesterday. ✅ (no passive)"
 },
 {
 "label": "exist",
 "title": "exist",
 "subtitle": "Problems exist. ✅ (no passive)"
 },
 {
 "label": "appear",
 "title": "emerge",
 "subtitle": "A ghost appeared. ✅ (no passive)"
 }
 ]
}

{
 "title": "2. Stative Verbs",
 "sections": [
 {
 "label": "Possession",
 "color": "rose",
 "description": "Verbs of <strong>possession</strong> are usually without the passive:",
 "examples": [
 {
 "en": "I have a car. ✅",
 "ua": "I have a car. ✅"
 },
 {
 "en": "She owns a house. ✅",
 "ua": "She owns a house. ✅"
 },
 {
 "en": "They possess great wealth. ✅",
 "ua": "They possess great wealth. ✅"
 }
 ]
 },
 {
 "label": "Conformity",
 "color": "amber",
 "description": "Verbs of <strong>conformity and similarity</strong>:",
 "examples": [
 {
 "en": "The dress fits her. ✅",
 "ua": "The dress fits her. ✅"
 },
 {
 "en": "This shirt suits you. ✅",
 "ua": "This shirt suits you. ✅"
 },
 {
 "en": "The key fits the lock. ✅",
 "ua": "The key fits the lock. ✅"
 }
 ]
 },
 {
 "label": "Content / content",
 "color": "blue",
 "description": "Verbs of <strong>capacity</strong>:",
 "examples": [
 {
 "en": "The hall holds 500 people. ✅",
 "ua": "The hall holds 500 people. ✅"
 },
 {
 "en": "The bottle contains water. ✅",
 "ua": "The bottle contains water. ✅"
 },
 {
 "en": "The bag weighs 5 kg. ✅",
 "ua": "The bag weighs 5 kg. ✅"
 }
 ]
 },
 {
 "label": "Reciprocity",
 "color": "emerald",
 "description": "Some <strong>reciprocal verbs</strong>:",
 "examples": [
 {
 "en": "Tom resembles his father. ✅",
 "ua": "Tom resembles his father. ✅"
 },
 {
 "en": "This equals that. ✅",
 "ua": "This equals that. ✅"
 },
 {
 "en": "They lack experience. ✅",
 "ua": "They lack experience. ✅"
 }
 ]
 }
 ]
}

{
 "title": "3. Transitive vs. Intransitive verbs",
 "intro": "Only <strong>transitive verbs</strong> (with a direct object) form the passive:",
 "rows": [
 {
 "en": "Transitive: They wrote a letter.",
 "ua": "Transitive: They wrote a letter.",
 "note": "→ Passive: A letter was written. ✅"
 },
 {
 "en": "Intransitive: He arrived late.",
 "ua": "Intransitive: He arrived late.",
 "note": "→ Passive: ❌ (no application)"
 },
 {
 "en": "Transitive: She opened the door.",
 "ua": "Transitive: She opened the door.",
 "note": "→ Passive: The door was opened. ✅"
 },
 {
 "en": "Intransitive: The door opened.",
 "ua": "Intransitive: The door opened.",
 "note": "→ Passive: ❌ (no application)"
 }
 ],
 "warning": "📌 Some verbs can be transitive and intransitive depending on the context!"
}

{
 "title": "4. Reflexive Verbs",
 "sections": [
 {
 "label": "Reverse actions",
 "color": "rose",
 "description": "When the subject and the object are <strong>the same</strong>, the passive is not used:",
 "examples": [
 {
 "en": "She washed herself. ✅",
 "ua": "She washed herself. ✅"
 },
 {
 "en": "He hurt himself. ✅",
 "ua": "He hurt himself. ✅"
 },
 {
 "en": "They enjoyed themselves. ✅",
 "ua": "They enjoyed themselves. ✅"
 }
 ]
 },
 {
 "label": "Mutual actions",
 "color": "blue",
 "description": "When the action is <strong>mutual</strong> (each other):",
 "examples": [
 {
 "en": "They love each other. ✅",
 "ua": "They love each other. ✅"
 },
 {
 "en": "We helped each other. ✅",
 "ua": "We helped each other. ✅"
 },
 {
 "en": "They met each other. ✅",
 "ua": "They met each other. ✅"
 }
 ]
 }
 ]
}

{
 "title": "5. Other restrictions",
 "intro": "Some constructions and meanings limit the passive:",
 "items": [
 {
 "label": "Cognate objects",
 "title": "related applications",
 "subtitle": "live a happy life, dream a dream — without the passive"
 },
 {
 "label": "Idioms",
 "title": "constant expressions",
 "subtitle": "keep an eye on — usually active"
 },
 {
 "label": "get + adj",
 "title": "change of state",
 "subtitle": "get angry, get tired is NOT a passive"
 },
 {
 "label": "let",
 "title": "allow",
 "subtitle": "He let me go. → I was allowed to go."
 }
 ]
}

{
 "title": "6. Verbs with a double meaning",
 "intro": "Some verbs have transitive and intransitive meanings:",
 "rows": [
 {
 "en": "run (transitive): They run a business.",
 "ua": "run (transitive): They run a business.",
 "note": "→ A business is run by them. ✅"
 },
 {
 "en": "run (intransitive): He runs every day.",
 "ua": "run (intransitive): He runs every day.",
 "note": "→ ❌ (no passive)"
 },
 {
 "en": "grow (transitive): They grow vegetables.",
 "ua": "grow (transitive): They grow vegetables.",
 "note": "→ Vegetables are grown. ✅"
 },
 {
 "en": "grow (intransitive): Children grow fast.",
 "ua": "grow (intransitive): Children grow fast.",
 "note": "→ ❌ (no passive)"
 }
 ],
 "warning": "📌 Check whether the verb has a direct object before forming the passive!"
}

{
 "title": "7. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Passive of an intransitive verb.",
 "wrong": "The accident was happened yesterday.",
 "right": "✅ The accident happened yesterday."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Passive of verbs of possession.",
 "wrong": "A nice house is had by her.",
 "right": "✅ She has a nice house."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "The passive of the reflexive verb.",
 "wrong": "Himself was cut by him.",
 "right": "✅ He cut himself."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Transitive/intransitive confusion.",
 "wrong": "He was arrived late.",
 "right": "✅ He arrived late."
 }
 ]
}
